% ForwardDifference% Approximating the derivative of exp(x) at x = 1 % by a finite difference formula%   x: the point we approximate the derivative%   h: a vector of stepsizes%   deriv: a vector of approximate derivatives%   error: a vector of absolute errorsclose allx = 1;h=1;disp(' ')disp('   i      h     finite difference    error')disp('-----------------------------------------')exponent = 1:16;h = 10.^(-exponent);deriv = (exp(x+h)-exp(x))./h; %forward differenceerror = deriv - exp(x);for i = 1:16  disp(sprintf(' %2.0f   %4.2e  %14.6f   %6.3e',i,h(i),deriv(i),error(i)))enddisp(' ')loglog(h,abs(error)); xlim([h(end),h(1)]);xlabel('h'),ylabel('|error|')title('Total error in Forward Difference Formula')       